    public void Calculate(Object index,Object lie) throws IOException {

        String lieArr = lie.toString();
        int cc_count = Integer.valueOf(index.toString());
        //右上角顶点
        double x_init = 121.1026188;  //+//最小经度值
        double y_init = 31.49927106;    //-//最大纬度值
        //最大与最小经度差值
        //x_jiange=(xmax-xmin)/508
        double x_jiange = 0.273829707/ 508;
        //最大与最小纬度差值
        //y_jiange=(ymax-ymin)/384
        double y_jiange = 0.269939954/ 384;
        List<message_value> list_ms = new ArrayList<>();

        int j = 0;
        if (cc_count > 0) j = (cc_count) * 72 + 4;//判断不情况的起始值。

        for (; j < (cc_count + 1) * 72 + 4; j++)
        {
            for (int i = 0; i < 384; i++)
            {
                double x_cha = x_init + x_jiange * j;   //横向 加
                double y_cha = y_init - y_jiange * i;   //纵向 加

                //循环对比实测所有坐标点值
                double juli_sum = 0;
                for (int x = 0; x < list_value.size(); x++)
                {
                    double _juli = Math.sqrt((x_cha - list_value.get(x).x) * (x_cha - list_value.get(x).x) + (y_cha - list_value.get(x).y) * (y_cha - list_value.get(x).y));
                    if (_juli < bijiao_x)
                    {
                        message_value _value = new message_value();
                        _value.juli = Math.pow(bijiao_x - _juli, 11);  //距离
                        juli_sum += _value.juli;        //求和作为权重
                        _value.sw = list_value.get(x).value;  //实测水位值
                        list_ms.add(_value);
                    }
                }

                //水位计算
                double _wgsw = 0;
                //根据最近距离权重法，计算网格值
                for (int z = 0; z < list_ms.size(); z++){
                    _wgsw += (list_ms.get(z).juli / juli_sum) * list_ms.get(z).sw;
                }
                list_ms.clear();
                sumAdd[i][j] = _wgsw;
            }
        }
        count_all++;


        System.out.println("count_all = "+ count_all);
        if (count_all == 7)
        {
            draw(lieArr);
        }
    }


